import network
import socket
import ussl
import json
from machine import Pin

# WiFi Configuration
SSID = 'your_SSID'
PASSWORD = 'your_PASSWORD'

# Initialize LED pin
led = Pin(2, Pin.OUT)

# Connect to WiFi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(SSID, PASSWORD)
    while not wlan.isconnected():
        pass
    print('Connected to WiFi:', wlan.ifconfig())

# WebSocket Handshake
def websocket_handshake(client):
    request = client.recv(1024)
    headers = {}
    for line in request.decode().splitlines():
        if ': ' in line:
            key, value = line.split(': ', 1)
            headers[key] = value
    webkey = headers['Sec-WebSocket-Key']
    webaccept = ussl.b64encode(ussl.sha1((webkey + '258EAFA5-E914-47DA-95CA-C5AB0DC85B11').encode()).digest()).decode()
    client.send(b'HTTP/1.1 101 Switching Protocols\r\n'
                b'Upgrade: websocket\r\n'
                b'Connection: Upgrade\r\n'
                b'Sec-WebSocket-Accept: ' + webaccept.encode() + b'\r\n\r\n')

# Handle WebSocket messages
def handle_message(message):
    try:
        command = json.loads(message)
        if 'action' in command:
            if command['action'] == 'turn_on':
                led.on()
                return json.dumps({"status": "LED turned on"})
            elif command['action'] == 'turn_off':
                led.off()
                return json.dumps({"status": "LED turned off"})
    except (ValueError, KeyError):
        return json.dumps({"error": "Invalid command"})

# Start WebSocket server
def start_server():
    addr = socket.getaddrinfo('0.0.0.0', 80)[0]
    s = socket.socket()
    s.bind(addr)
    s.listen(1)
    print('Listening on', addr)

    while True:
        client, addr = s.accept()
        print('Client connected from', addr)
        websocket_handshake(client)
        while True:
            try:
                msg = client.recv(1024)
                if not msg:
                    break
                response = handle_message(msg)
                client.send(response.encode())
            except Exception as e:
                print('Error:', e)
                break
        client.close()

# Main execution
connect_wifi()
start_server()